import{waitForAuth,isAdmin,isStaff,getCurrentUser}from '../shared/guard-utils.js';(async function adminGuard(){const isLocalhost=['localhost','127.0.0.1',''].includes(window.location.hostname);if(isLocalhost){return;}try{await waitForAuth(5000);await window.Auth.State.init();if(!window.Auth.State.isAuthenticated){const currentPath=window.location.pathname;const redirectParam=encodeURIComponent(currentPath+window.location.search);window.location.replace(`/auth/login.html?redirect=${redirectParam}`);return;}if(isAdmin()||isStaff()){window.__ADMIN_USER__={id: window.Auth.State.user?.id,email: window.Auth.State.user?.email,role: window.Auth.State.getRole?.(),profile: window.Auth.State.profile};}else{const role=window.Auth.State.getRole?.();const ROLE_REDIRECTS={'client': '/portal/dashboard.html','affiliate': '/affiliate/dashboard.html'};const redirectUrl=ROLE_REDIRECTS[role]||'/';window.location.replace(redirectUrl);return;}window.addEventListener('auth:signout',()=>{window.location.replace('/auth/login.html');});}catch(error){}})();